module shiftreg16(d, clk, rst, q);
    input d;
    input clk;
    input rst;
    output reg [15:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 16'b0;
        else
            q <= {q[14:0], d};
    end
endmodule
